    end)
    self:ModelNetMsgRecv(LProtoIds.CollegeReportResp, function(...)
        self:OnCollegeReportResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.CollegeLibraryRewardResp, function(...)
        self:OnCollegeLibraryRewardResp(...)
    end)
end

