---req
function ModelCareSchool:OnCollegeInfoReq()
    --请求魔导学院相关数据
    local pb = LProtoHelper.CreateProto(LProtoIds.CollegeInfoReq)
    SendMessage(pb, LProtoIds.CollegeInfoReq)
end

function ModelCareSchool:OnCollegeReportReq(refId)
    --战术马戏团战报
    local pb = LProtoHelper.CreateProto(LProtoIds.CollegeReportReq)
    pb.refId = refId
    SendMessage(pb, LProtoIds.CollegeReportReq)
end
function ModelCareSchool:OnCollegeLibraryRewardReq(refId)
    if nil == refId or refId == 0 then
        return
    end

    local pb = LProtoHelper.CreateProto(LProtoIds.CollegeLibraryRewardReq)
    pb.refId = refId
    SendMessage(pb, LProtoIds.CollegeLibraryRewardReq)
end
-------------------------------------------
---resp
function ModelCareSchool:OnCollegeInfoResp(pb)
    --返回魔导学院相关数据
    local collegeInfo = pb.collegeInfo
    local libraryDo = collegeInfo.libraryDo
    local receiveRefIds = collegeInfo.receiveRefIds or {}
    local libraryDoList = self:GetLibraryDoList()
    for i, v in ipairs(libraryDo) do
        libraryDoList[v] = v
    end
    self._libraryDoList = libraryDoList
    local _receiveRefIds = {}
    for i, v in ipairs(receiveRefIds) do
        _receiveRefIds[v] = true
    end
    self._receiveRefIds = _receiveRefIds

    local simulationHurt = collegeInfo.simulationHurt
    local simulationHurtList = self:GetSimulationHurtList()
    for i, v in ipairs(simulationHurt) do
        local refId = v.refId
        local hurt = v.hurt
        simulationHurtList[refId] = hurt
    end
    self._simulationHurtList = simulationHurtList
end

function ModelCareSchool:OnCollegeReportResp(pb)
    local refId = pb.refId
    local reports = pb.reports
    local _reports = {}
    for i, v in ipairs(reports) do
        local info = StructCollegeReportInfo:New()
        info:CreateByPb(v)
        table.insert(_reports, info)
    end
    self._reports[refId] = _reports
end
function ModelCareSchool:OnCollegeLibraryRewardResp(pb)
end
