function ModelCareSchool:GetLibraryChapterNum(refId)
    --获取总关卡数和通关的关卡数
    local list = self:GetCollegeLibraryCheckpointRefListByRefId(refId)
    local len = #list
    if len <= 0 then
        return len, len
    end
    local num = 0
    local _libraryDoList = self:GetLibraryDoList()
    for i, v in ipairs(list) do
        if _libraryDoList[v.refId] then
            num = num + 1
        end
    end
    return len, num
end

