function ModelCareSchool:GetInitFromation(targetId, _formationGrid)
    local heroDataList = {}
    local ref = gModelCareSchool:GetCollegeLibraryCheckpointRefByRefId(targetId)
    if ref.mustHero == "" then
        return heroDataList
    end
    local mustHero = string.split(ref.mustHero, ",")
    for i, v in ipairs(mustHero) do
        local hero = string.split(v, "=")
        local heroId = tonumber(hero[1])
        local posIndex = tonumber(hero[2])

        local monsterRef = gModelHero:GetMonsterAttrByRefId(heroId)
        local effRef = gModelHero:GetShowEffectById(monsterRef.effectId)
        local bottomImg = gModelHero:GetMonsterBottomImgByRefId(heroId)
        local data = {
            heroId = heroId,
            pbName = effRef.prefabName,
            bottomImg = bottomImg,
            pos = posIndex,
            race = monsterRef.raceType,
            level = monsterRef.lv,
            scale = monsterRef and monsterRef.scale or 0.8,
            root = _formationGrid and _formationGrid:GetFigureRoot(posIndex, not true) or nil,
            isResonance = 0,
            refId = monsterRef.effectId,
            curHp = monsterRef.MaxHP,
            maxHp = monsterRef.MaxHP
        }
        heroDataList[posIndex] = data
    end
    return heroDataList
end

function ModelCareSchool:SaveMirrorFormation(side, data)
    if not self._formationMap then
        self._formationMap = {}
    end

    self._formationMap[side] = data
end

function ModelCareSchool:GetMirrorFormationData(side)
    return self._formationMap and self._formationMap[side]
end

function ModelCareSchool:ClearMirrorData()
    self._formationMap = nil
end

